class Solution:
    def possibleToStamp(self, grid, stampHeight, stampWidth) -> bool:
        m = len(grid)
        n = len(grid[0]) if m else 0
        covered = [[False] * n for _ in range(m)]
        for i in range(m - stampHeight + 1):
            for j in range(n - stampWidth + 1):
                fits = True
                for r in range(i, i + stampHeight):
                    if not fits:
                        break
                    for c in range(j, j + stampWidth):
                        if grid[r][c] == 1:
                            fits = False
                            break
                if fits:
                    for r in range(i, i + stampHeight):
                        for c in range(j, j + stampWidth):
                            covered[r][c] = True
        for i in range(m):
            for j in range(n):
                if grid[i][j] == 0 and not covered[i][j]:
                    return False
        return True

