var possibleToStamp = function(grid, stampHeight, stampWidth) {
    const m = grid.length;
    const n = m ? grid[0].length : 0;
    const prefix = Array.from({ length: m + 1 }, () => new Array(n + 1).fill(0));
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            prefix[i + 1][j + 1] = grid[i][j] + prefix[i][j + 1] + prefix[i + 1][j] - prefix[i][j];
        }
    }
    const regionSum = (r1, c1, r2, c2) => prefix[r2][c2] - prefix[r1][c2] - prefix[r2][c1] + prefix[r1][c1];
    const diff = Array.from({ length: m + 1 }, () => new Array(n + 1).fill(0));
    for (let i = 0; i + stampHeight <= m; i++) {
        for (let j = 0; j + stampWidth <= n; j++) {
            if (regionSum(i, j, i + stampHeight, j + stampWidth) === 0) {
                diff[i][j] += 1;
                diff[i + stampHeight][j] -= 1;
                diff[i][j + stampWidth] -= 1;
                diff[i + stampHeight][j + stampWidth] += 1;
            }
        }
    }
    const cover = Array.from({ length: m + 1 }, () => new Array(n + 1).fill(0));
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            cover[i + 1][j + 1] = diff[i][j] + cover[i][j + 1] + cover[i + 1][j] - cover[i][j];
            if (grid[i][j] === 0 && cover[i + 1][j + 1] <= 0) {
                return false;
            }
        }
    }
    return true;
};
